const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const body = $input.item.json.body || $input.item.json;
const senderId = String(body.sender || '').replace('@c.us', '').replace('@lid', '').trim();
const question = (body.message || $input.item.json.message || '').trim();
// Debug line — remove after testing

if (!question) return { answer: '' };

// ============================================
// Guest access helpers
// ============================================
function loadGuests() {
  try { return JSON.parse(fs.readFileSync(config.guests_file, 'utf8')); } catch(e) { return []; }
}

function isOwner() {
  const waOwner = config.whatsapp_owner_phone ? String(config.whatsapp_owner_phone).trim() : null;
  const tgOwner = String(config.telegram_chat_id).trim();
  return senderId === tgOwner || (waOwner && senderId === waOwner);
}

function getGuest() {
  const guests = loadGuests();
  const today = new Date().toISOString().split('T')[0];
  return guests.find(g => String(g.whatsapp_phone).trim() === senderId && g.expires >= today) ||
         guests.find(g => String(g.telegram_id).trim() === senderId && g.expires >= today) || null;
}

// ============================================
// Owner flow
// ============================================
if (isOwner()) {

  if (question.startsWith('http')) return { answer: '' };

  // /list command
  if (question.toLowerCase().startsWith('/list') || question.toLowerCase().startsWith('list ')) {
    const listCategory = question.toLowerCase().replace(/^\/?list\s+/, '').replace(/[^a-z0-9]/g, '');
    if (!listCategory) return { answer: 'Usage: /list <category>\nExample: /list travel' };
    const filepath = config.knowledge_dir + '/' + listCategory + '.md';
    try {
      const content = fs.readFileSync(filepath, 'utf8');
      const entries = content.split('---').filter(e => e.trim() && e.includes('##'));
      if (entries.length === 0) return { answer: 'No saved links in category: ' + listCategory };
      const list = entries.map((e, i) => {
        const titleMatch = e.match(/## \[(.+?)\]\((.+?)\)/);
        const dateMatch = e.match(/\*\*Saved:\*\* (.+)/);
        if (titleMatch) return `${i + 1}. ${titleMatch[1]}\n${titleMatch[2]}\n📅 ${dateMatch?.[1] || ''}`;
        return null;
      }).filter(Boolean).join('\n\n');
      return { answer: `📂 ${listCategory} — ${entries.length} saved links\n\n${list}` };
    } catch(e) {
      return { answer: 'No saved links in category: ' + listCategory };
    }
  }

  // /invite command
  if (question.toLowerCase().startsWith('/invite')) {
    const parts = question.split(' ');
    if (parts.length < 4) {
      return { answer: 'Usage: /invite phone=<number> <categories> <duration>\nExample: /invite phone=YOUR_PHONE_NUMBER travel,food 7days' };
    }
    const target = parts[1];
    const categories = parts[2].toLowerCase().split(',').map(c => c.trim().replace(/[^a-z0-9]/g, ''));
    const durationStr = parts[3].toLowerCase();
    let expires;
    if (durationStr === 'permanent') {
      expires = '9999-12-31';
    } else {
      const amount = parseInt(durationStr);
      const unit = durationStr.replace(/[0-9]/g, '');
      const d = new Date();
      if (unit.startsWith('day')) d.setDate(d.getDate() + amount);
      else if (unit.startsWith('week')) d.setDate(d.getDate() + amount * 7);
      else if (unit.startsWith('month')) d.setMonth(d.getMonth() + amount);
      expires = d.toISOString().split('T')[0];
    }
    const guests = loadGuests();
    let newGuest = { categories, expires, added: new Date().toISOString().split('T')[0] };
    if (target.startsWith('phone=')) newGuest.whatsapp_phone = target.replace('phone=', '');
    else if (target.startsWith('id=')) newGuest.telegram_id = target.replace('id=', '');
    else newGuest.telegram_id = target;
    const key = newGuest.whatsapp_phone || newGuest.telegram_id;
    const existingIdx = guests.findIndex(g =>
      (g.whatsapp_phone && g.whatsapp_phone === newGuest.whatsapp_phone) ||
      (g.telegram_id && g.telegram_id === newGuest.telegram_id)
    );
    if (existingIdx >= 0) guests[existingIdx] = newGuest; else guests.push(newGuest);
    fs.writeFileSync(config.guests_file, JSON.stringify(guests, null, 2), 'utf8');
    return { answer: '✅ Guest access granted\n\nFor: ' + key + '\nCategories: ' + categories.join(', ') + '\nExpires: ' + expires };
  }

  // /guests command
  if (question.toLowerCase().startsWith('/guests')) {
    const guests = loadGuests();
    const today = new Date().toISOString().split('T')[0];
    const active = guests.filter(g => g.expires >= today);
    if (active.length === 0) return { answer: 'No active guests.' };
    const list = active.map((g, i) =>
      `${i + 1}. ${g.whatsapp_phone ? 'WhatsApp: ' + g.whatsapp_phone : 'Telegram: ' + g.telegram_id}\n   Categories: ${g.categories.join(', ')}\n   Expires: ${g.expires}`
    ).join('\n\n');
    return { answer: '👥 Active guests (' + active.length + '):\n\n' + list };
  }

  // /revoke command
  if (question.toLowerCase().startsWith('/revoke')) {
    const target = question.split(' ')[1];
    if (!target) return { answer: 'Usage: /revoke <phone_or_telegram_id>' };
    let guests = loadGuests();
    const before = guests.length;
    guests = guests.filter(g => g.whatsapp_phone !== target && String(g.telegram_id) !== target);
    fs.writeFileSync(config.guests_file, JSON.stringify(guests, null, 2), 'utf8');
    return { answer: before > guests.length ? '✅ Access revoked for ' + target : '❌ Guest not found: ' + target };
  }

  // Handle greetings
  const greetings = ['hi','hello','hey','مرحبا','هلا','السلام','صباح','مساء'];
  if (greetings.some(g => question.toLowerCase().startsWith(g))) {
    return { answer: 'أهلاً! اسألني عن أي شيء حفظته 👋' };
  }

  // Owner full knowledge query
  const dir = config.knowledge_dir;
  let knowledge = '';
  let fileCount = 0;
  try {
    const files = fs.readdirSync(dir).filter(f => f.endsWith('.md'));
    fileCount = files.length;
    for (const file of files) {
      try {
        const content = fs.readFileSync(dir + '/' + file, 'utf8');
        if (content.trim()) knowledge += '\n\n=== ' + file.replace('.md', '') + ' ===\n' + content.slice(0, 2000);
      } catch(e) {}
    }
  } catch(e) {}
  if (!knowledge.trim()) knowledge = 'No saved links yet.';
  else knowledge = knowledge.slice(0, 20000);

  const groqResponse = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.groq_api_key },
    body: { model: 'llama-3.3-70b-versatile', temperature: 0.2, messages: [
      { role: 'system', content: 'You are a personal knowledge assistant. Answer questions using only the saved links provided. Be concise and helpful. For each relevant item include the title and URL. If nothing matches, say so clearly. Respond in the same language as the question.' },
      { role: 'user', content: 'My saved links (' + fileCount + ' categories):\n' + knowledge + '\n\nQuestion: ' + question }
    ]}
  });
  return { answer: groqResponse.choices?.[0]?.message?.content || 'Could not get an answer.' };
}

// ============================================
// Guest flow
// ============================================
const guest = getGuest();

if (!guest) {
  return { answer: 'مرحباً! ليس لديك صلاحية للوصول.\n\nHello! You do not have access. Contact the bot owner for an invite.' };
}

if (question.startsWith('http') || question.startsWith('/') || question.match(/^[\w-]+\.(com|net|org|io|co|app|dev)/i)) {
  return { answer: 'Guests can only ask questions about saved links.' };
}

const guestGreetings = ['hi','hello','hey','مرحبا','هلا','السلام','صباح','مساء'];
if (guestGreetings.some(g => question.toLowerCase().startsWith(g))) {
  return { answer: 'أهلاً! يمكنك الاستفسار عن: ' + guest.categories.join(', ') + '\n\nHello! You can ask about: ' + guest.categories.join(', ') };
}

let guestKnowledge = '';
let guestFileCount = 0;
for (const cat of guest.categories) {
  try {
    const content = fs.readFileSync(config.knowledge_dir + '/' + cat + '.md', 'utf8');
    if (content.trim()) { guestKnowledge += '\n\n=== ' + cat + ' ===\n' + content.slice(0, 2000); guestFileCount++; }
  } catch(e) {}
}

if (!guestKnowledge.trim()) {
  return { answer: 'No saved links found in your allowed categories: ' + guest.categories.join(', ') };
}

const guestGroqResponse = await this.helpers.httpRequest({
  method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.groq_api_key },
  body: { model: 'llama-3.3-70b-versatile', temperature: 0.2, messages: [
    { role: 'system', content: 'You are a helpful knowledge assistant. Answer questions using only the saved links provided. Be concise and include titles and URLs. Respond in the same language as the question.' },
    { role: 'user', content: 'Saved links (' + guestFileCount + ' categories):\n' + guestKnowledge.slice(0, 20000) + '\n\nQuestion: ' + question }
  ]}
});

return { answer: guestGroqResponse.choices?.[0]?.message?.content || 'Could not get an answer.' };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));
const answer = $('Handle WhatsApp message').item.json.answer;
if (!answer) return { sent: false };
return { answer, sent: true };
